  const ip = req.ip;
  const customHeader = req.headers['x-custom-header'] || '';
  const rawUserInput = req.body?.message || req.query?.message || '';

  logger.info(`audit username=${username} ip=${ip} customHeader=${customHeader} input=${rawUserInput}`);
